// PreloadCount sets a count in the C struct by name
func (o *Event) PreloadCount(name string, count int64) error {
	if o == nil {
		return nil
	}

	switch name {
	case "BookingEntries":
		o.C.BookingEntries = &count
	case "EventDriverStandings":
		o.C.EventDriverStandings = &count
	case "EventProcessingAudits":
		o.C.EventProcessingAudits = &count
	case "EventTeamStandings":
		o.C.EventTeamStandings = &count
	case "Races":
		o.C.Races = &count
	}
	return nil
}

